diff --git a/include/spdlog/sinks/dup_filter_sink.h b/include/spdlog/sinks/dup_filter_sink.h
index 1071e98..661f00b 100644
--- a/include/spdlog/sinks/dup_filter_sink.h
+++ b/include/spdlog/sinks/dup_filter_sink.h
@@ -47,6 +47,7 @@ protected:
     std::chrono::microseconds max_skip_duration_;
     log_clock::time_point last_msg_time_;
     std::string last_msg_payload_;
+    level::level_enum last_msg_level_ = spdlog::level::level_enum::off;
     size_t skip_counter_ = 0;
     level::level_enum skipped_msg_log_level_ = spdlog::level::level_enum::off;

@@ -75,12 +76,14 @@ protected:
         last_msg_time_ = msg.time;
         skip_counter_ = 0;
         last_msg_payload_.assign(msg.payload.data(), msg.payload.data() + msg.payload.size());
+        last_msg_level_ = msg.level;
     }

     // return whether the log msg should be displayed (true) or skipped (false)
     bool filter_(const details::log_msg &msg) const {
         const auto filter_duration = msg.time - last_msg_time_;
-        return (filter_duration > max_skip_duration_) || (msg.payload != last_msg_payload_);
+        return (filter_duration > max_skip_duration_) || (msg.payload != last_msg_payload_) ||
+               (msg.level != last_msg_level_);
     }
